// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Task card sub-component
function TaskCard({
  task,
  onMove,
  onEdit,
  availableColumns,
}: {
  task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };
  onMove: (taskId: string, columnId: string) => void;
  onEdit: (taskId: string, title: string) => void;
  availableColumns: Array<{ id?: string; name?: string }>;
}) {
  const [isEditing, setIsEditing] = useState(false);
  const [editedTitle, setEditedTitle] = useState(task.title || '');
  const [showMoveMenu, setShowMoveMenu] = useState(false);

  const handleSaveEdit = () => {
    if (editedTitle.trim() && task.id) {
      onEdit(task.id, editedTitle);
      setIsEditing(false);
    }
  };

  const getPriorityColor = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'success';
      default:
        return 'default';
    }
  };

  return (
    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md">
      <Stack gap="var(--ggui-spacing-2)">
        {isEditing ? (
          <Stack gap="var(--ggui-spacing-2)" direction="horizontal">
            <Input
              label="Task title"
              value={editedTitle}
              onChange={setEditedTitle}
              size="sm"
            />
            <Button size="sm" variant="primary" onClick={handleSaveEdit}>
              Save
            </Button>
          </Stack>
        ) : (
          <Row align="center" justify="between">
            <Text
              variant="body"
              truncate
              style={{ flex: 1, cursor: 'pointer' }}
              as={Clickable}
              onClick={() => setIsEditing(true)}
            >
              {task.title || 'Untitled'}
            </Text>
            <Button size="xs" variant="ghost" onClick={() => setIsEditing(true)}>
              Edit
            </Button>
          </Row>
        )}

        {task.priority && (
          <Badge variant={getPriorityColor(task.priority)} size="sm" pill>
            {task.priority}
          </Badge>
        )}

        <Row align="center" justify="between" gap="var(--ggui-spacing-2)">
          {task.assignee && (
            <Tooltip content={task.assignee} position="bottom">
              <Avatar name={task.assignee} size="sm" />
            </Tooltip>
          )}
          {task.dueDate && (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              {new Date(task.dueDate).toLocaleDateString()}
            </Text>
          )}
        </Row>

        <Dropdown
          trigger={<Button size="xs" variant="outline">Move</Button>}
          options={availableColumns
            .filter((c) => c.id !== task.column)
            .map((c) => ({ value: c.id || '', label: c.name || 'Unknown' }))}
          value=""
          onChange={(columnId) => {
            if (task.id) onMove(task.id, columnId);
            setShowMoveMenu(false);
          }}
          placement="bottom-start"
        />
      </Stack>
    </Card>
  );
}


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local state for tasks (merged from props + stream updates)
  const [localTasks, setLocalTasks] = useState(props.tasks || []);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [showAddTask, setShowAddTask] = useState(false);

  // Merge stream updates into local tasks
  useEffect(() => {
    if (taskChanged.latest?.task) {
      const updatedTask = taskChanged.latest.task;
      const action = taskChanged.latest.action;

      if (action === 'delete' && updatedTask.id) {
        setLocalTasks((prev) => prev.filter((t) => t.id !== updatedTask.id));
      } else if (action === 'create' && updatedTask.id) {
        setLocalTasks((prev) => [...prev, updatedTask]);
      } else if (updatedTask.id) {
        setLocalTasks((prev) =>
          prev.map((t) => (t.id === updatedTask.id ? updatedTask : t))
        );
      }
    }
  }, [taskChanged.latest]);

  // Handlers
  const handleMoveTask = useCallback(
    (taskId: string, columnId: string) => {
      setLocalTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, column: columnId } : t))
      );
      taskUpdate({ action: 'move', taskId, data: { column: columnId } });
    },
    [taskUpdate]
  );

  const handleEditTask = useCallback(
    (taskId: string, title: string) => {
      setLocalTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, title } : t))
      );
      taskUpdate({ action: 'edit', taskId, data: { column: '' } });
    },
    [taskUpdate]
  );

  const handleAddTask = useCallback(() => {
    if (newTaskTitle.trim()) {
      const newTask = {
        id: `task-${Date.now()}`,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: props.columns?.[0]?.id || 'todo',
      };
      setLocalTasks((prev) => [...prev, newTask]);
      taskUpdate({
        action: 'create',
        taskId: newTask.id,
        data: { column: newTask.column },
      });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setShowAddTask(false);
    }
  }, [newTaskTitle, newTaskPriority, props.columns, taskUpdate]);

  // Compute summary stats
  const totalTasks = localTasks.length;
  const completedTasks = localTasks.filter((t) => t.column === 'done').length;

  // Group tasks by column
  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, typeof localTasks> = {};
    props.columns?.forEach((col) => {
      grouped[col.id || ''] = [];
    });
    localTasks.forEach((task) => {
      const colId = task.column || '';
      if (!grouped[colId]) grouped[colId] = [];
      grouped[colId].push(task);
    });
    return grouped;
  }, [localTasks, props.columns]);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm" background="var(--ggui-color-primary-50)">
          <Row align="center" justify="between">
            <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center">
              <Heading level={3} color="var(--ggui-color-primary-900)">
                Task Board
              </Heading>
              <Text variant="label" color="var(--ggui-color-primary-700)">
                {completedTasks} of {totalTasks} completed
              </Text>
            </Stack>
            <Progress value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0} max={100} variant="success" size="md" />
          </Row>
        </Card>

        {/* Add Task Form */}
        {showAddTask && (
          <Card padding="var(--ggui-spacing-4)" shadow="sm">
            <Stack gap="var(--ggui-spacing-3)">
              <Heading level={4}>Add New Task</Heading>
              <Input
                label="Task Title"
                placeholder="Enter task title"
                value={newTaskTitle}
                onChange={setNewTaskTitle}
              />
              <Select
                label="Priority"
                value={newTaskPriority}
                onChange={(v) => setNewTaskPriority(v as 'low' | 'medium' | 'high')}
                options={[
                  { value: 'low', label: 'Low' },
                  { value: 'medium', label: 'Medium' },
                  { value: 'high', label: 'High' },
                ]}
              />
              <Row gap="var(--ggui-spacing-2)" justify="end">
                <Button variant="ghost" onClick={() => setShowAddTask(false)}>
                  Cancel
                </Button>
                <Button variant="primary" onClick={handleAddTask}>
                  Add Task
                </Button>
              </Row>
            </Stack>
          </Card>
        )}

        {/* Kanban Board */}
        <Row gap="var(--ggui-spacing-4)" align="start">
          {props.columns?.map((column) => {
            const columnTasks = tasksByColumn[column.id || ''] || [];

            return (
              <Box key={column.id} style={{ flex: '1 1 320px', minWidth: '300px' }}>
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Column Header */}
                  <Card padding="var(--ggui-spacing-3)" shadow="sm" background="var(--ggui-color-surfaceVariant)">
                    <Row align="center" justify="between">
                      <Heading level={4} color="var(--ggui-color-onSurface)">{column.name}</Heading>
                      <Badge variant="default" size="sm" pill>
                        {columnTasks.length}
                      </Badge>
                    </Row>
                  </Card>

                  {/* Task List */}
                  <Stack gap="var(--ggui-spacing-2)" style={{ minHeight: '400px' }}>
                    {columnTasks.length > 0 ? (
                      columnTasks.map((task) => (
                        <TaskCard
                          key={task.id}
                          task={task}
                          onMove={handleMoveTask}
                          onEdit={handleEditTask}
                          availableColumns={props.columns || []}
                        />
                      ))
                    ) : (
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" align="center">
                        No tasks
                      </Text>
                    )}
                  </Stack>

                  {/* Add Task Button */}
                  {!showAddTask && (
                    <Button
                      variant="outline"
                      fullWidth
                      onClick={() => setShowAddTask(true)}
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}
}
